public class TournamentWinner {

    public static void main(String[] args) {
        int[] arr = {2, 1, 3, 4, 5};
        int k = 2;
        System.out.println("Winner: " + tournament(arr, k));
    }

    private static int tournament(int[] array, int k) {
        int currentWinner = array[0];
        int currentWins = 0;

        for (int i = 1; i < array.length; i++) {
            if (currentWinner > array[i]) {
                currentWins++;
                if (currentWins == k) {
                    return currentWinner;
                }
            } else {
                currentWinner = array[i];
                currentWins = 1;
            }
        }

        // If no player wins k matches in a row, the strongest player is the winner.
        return currentWinner;
    }
}

