func tournamentWinner(arr: [Int], streak: Int) -> Int {
    var arr = arr
    var winner = arr[0]
    var wins = 0

    for i in 1..<arr.count {
        let num = arr[i]

        if winner < num {
            arr.append(winner)
            winner = num
            wins = 1
        } else {
            arr.append(num)
            wins += 1
        }

        if wins == streak {
            return winner
        }
    }

    return winner
}
